import React, { useState } from 'react';

export default function Breadcrumbs({ path, maxItems = 4 }) {
  const segments = path.split('/').filter(Boolean);
  const [isExpanded, setIsExpanded] = useState(false);

  const items = segments.map((seg, idx) => {
    const href = '/' + segments.slice(0, idx + 1).join('/');
    const label = seg.charAt(0).toUpperCase() + seg.slice(1).replace(/-/g, ' ');
    return { label, href };
  });

  const shouldCollapse = items.length > maxItems && !isExpanded;

  const renderItems = () => {
    if (shouldCollapse) {
      const first = items[0];
      const lastTwo = items.slice(-2);
      return [
        first,
        { label: "...", isEllipsis: true },
        ...lastTwo
      ];
    }
    return items;
  };

  const visibleItems = renderItems();

  return (
    <nav aria-label="Breadcrumb" className="text-sm select-none">
      <ol className="flex items-center gap-2 text-gray-500 font-medium">
        <li>
          <a href="/" className="hover:text-purple-600 transition flex items-center">
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
          </a>
        </li>

        {visibleItems.map((item, idx) => {
          const isLast = idx === visibleItems.length - 1;

          return (
            <React.Fragment key={idx}>
              <svg className="w-3 h-3 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
              </svg>
              <li>
                {item.isEllipsis ? (
                  <button onClick={() => setIsExpanded(true)} className="hover:text-purple-600 transition font-bold px-1 focus:outline-none">
                    ...
                  </button>
                ) : isLast ? (
                  <span className="text-gray-800 font-bold" aria-current="page">
                    {item.label}
                  </span>
                ) : (
                  <a href={item.href} className="hover:text-purple-600 transition">
                    {item.label}
                  </a>
                )}
              </li>
            </React.Fragment>
          );
        })}
      </ol>
    </nav>
  );
}
